from flask import Flask, request, jsonify
import secrets

app = Flask(__name__)

auth_codes = {}

@app.route('/authorize', methods=['POST'])
def authorize():
    user_id = request.json.get('user_id')
    code = secrets.token_urlsafe(16)
    auth_codes[code] = user_id
    return jsonify({'authorization_code': code}), 201

@app.route('/token', methods=['POST'])
def token():
    code = request.json.get('authorization_code')
    if code in auth_codes:
        user_id = auth_codes[code]
        return jsonify({'access_token': secrets.token_urlsafe(32), 'user_id': user_id}), 200
    return jsonify({'error': 'invalid_grant'}), 400

if __name__ == '__main__':
    app.run(debug=True)